import { forwardRef } from "react";
import {
  Link as AriaLink,
  type LinkProps as AriaLinkProps,
} from "react-aria-components";
import * as styles from "./_BaseLink.css";
import { clsx } from "clsx";

/**
 * Props for the internal BaseLink component.
 * Extends React Aria's LinkProps with design system conventions.
 */
export interface BaseLinkProps extends AriaLinkProps {
  /**
   * Additional CSS class name(s) to apply to the link.
   */
  className?: string;

  /**
   * When true, bypasses client-side routing and performs a full browser navigation.
   * Useful for crossing app boundaries that are served on the same origin, navigating to legacy page or external pages.
   */
  fullPageNavigation?: boolean;
}

/**
 * @internal
 * Base link component providing accessible link behavior without visual styling.
 *
 * This is an internal primitive for use within the design system. It wraps
 * React Aria's Link component to provide:
 * - Proper keyboard navigation and focus management
 * - Client-side routing integration (when RouterProvider is configured)
 * - Accessible press handling (keyboard, mouse, touch)
 * - Support for disabled state
 *
 * Use this instead of raw `<a>` tags when building DS components that need
 * link behavior. The future designed Link component will build on top of this.
 *
 * @example
 * // Inside a DS component like Breadcrumbs
 * <_BaseLink href="/home" className={styles.breadcrumbLink}>
 *   Home
 * </_BaseLink>
 *
 * // Full navigation (bypasses client-side routing)
 * <_BaseLink href="/legacy" fullPageNavigation>
 *   Legacy Page
 * </_BaseLink>
 */
export const _BaseLink = forwardRef<HTMLAnchorElement, BaseLinkProps>(
  ({ className, fullPageNavigation, routerOptions, ...props }, ref) => {
    // Merge fullPageNavigation into routerOptions, only passing it when defined
    const mergedRouterOptions = fullPageNavigation
      ? { ...routerOptions, fullPageNavigation: true }
      : routerOptions;

    return (
      <AriaLink
        ref={ref}
        className={clsx(styles.baseLink, className)}
        {...(mergedRouterOptions && { routerOptions: mergedRouterOptions })}
        {...props}
      />
    );
  }
);

_BaseLink.displayName = "_BaseLink";
